class SecureKeyManager {
  constructor() {
    // Encryption key derived from a master password stored in environment
    // In production, use AWS KMS, HashiCorp Vault, or similar HSM/KMS solution
    const masterKey = process.env.MASTER_ENCRYPTION_KEY;
    if (!masterKey) {
      throw new Error(
        'MASTER_ENCRYPTION_KEY must be set in environment variables. ' +
        'Use a secure secret manager in production.'
      );
    }
    this.encryptionKey = crypto.scryptSync(masterKey, 'dapp-backend-salt', 32);
    this.keystorePath = process.env.KEYSTORE_PATH || path.join(__dirname, '.keystore');

    if (!fs.existsSync(this.keystorePath)) {
      fs.mkdirSync(this.keystorePath, { mode: 0o700, recursive: true });
    }
  }

  /**
   * Encrypts a private key and stores it on disk (or could store in a database).
   * In production, prefer a dedicated KMS (AWS KMS, GCP KMS, Azure Key Vault).
   */
  storeKey(alias, privateKey) {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv('aes-256-gcm', this.encryptionKey, iv);
    let encrypted = cipher.update(privateKey, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag();

    const payload = {
      iv: iv.toString('hex'),
      authTag: authTag.toString('hex'),
      encrypted,
    };

    const filePath = path.join(this.keystorePath, `${alias}.json`);
    fs.writeFileSync(filePath, JSON.stringify(payload), { mode: 0o600 });
    console.log(`Key stored securely for alias: ${alias}`);
  }

  /**
   * Retrieves and decrypts a private key by alias.
   */
  retrieveKey(alias) {
    const filePath = path.join(this.keystorePath, `${alias}.json`);
    if (!fs.existsSync(filePath)) {
      throw new Error(`No key found for alias: ${alias}`);
    }

    const payload = JSON.parse(fs.readFileSync(filePath, 'utf8'));
    const iv = Buffer.from(payload.iv, 'hex');
    const authTag = Buffer.from(payload.authTag, 'hex');

    const decipher = crypto.createDecipheriv('aes-256-gcm', this.encryptionKey, iv);
    decipher.setAuthTag(authTag);
    let decrypted = decipher.update(payload.encrypted, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  /**
   * Creates a wallet signer from a stored key. The private key is held in
   * memory only for the duration of the signer's use.
   */
  getWallet(alias, provider) {
    const privateKey = this.retrieveKey(alias);
    const wallet = new ethers.Wallet(privateKey, provider);
    return wallet;
  }
}

